patterns.template:
# Assert delta={delta} within {ms}ms.
before = fetch_indexeddb_count(page)
page.wait_for_timeout({ms})
after = fetch_indexeddb_count(page)
EVIDENCE['checks']['delta_within_ms'] = {{
    'before': before, 'after': after, 'delta': after - before,
    'expected_delta': {delta}, 'window_ms': {ms},
    'pass': (after - before) >= {delta}
}}

# Assert sum identity within ±{pct}%.
sample = (fetch_indexeddb_entries(page, limit=1) or [None])[0]
if sample:
    s = (sample.get('server_ms') or 0) + (sample.get('net_up_ms') or 0) + (sample.get('net_down_ms') or 0)
    t = sample.get('total_ms') or 0
    diff_pct = abs(s - t) / t if t else 1.0
    EVIDENCE['checks']['sum_within_pct'] = {{
        'sum': s, 'total': t, 'diff_pct': diff_pct,
        'threshold': {pct}/100.0, 'pass': diff_pct <= {pct}/100.0
    }}
